@ARTICLE{10.2174/1567201817666200527133719,
	author = {Chadha S and Kumar A and Srivastava SA and Behl T and Ranjan R},
	title = {Inulin as a Delivery Vehicle for Targeting Colon-Specific Cancer.},
	journal = {Curr Drug Deliv},
	year = {2020},
	abstract = {Natural polysaccharides, as well as biopolymers, are now days widely developed for targeting colon cancer using various drug delivery systems. Currently, healing conformations are being explored that can efficiently play a multipurpose role. Owing to the capability of extravagance colonic diseases with the least adverse effects, biopolymers for site specific colon delivery have developed an increased curiosity over the past decades. Inulin (INU) was explored for its probable application as an entrapment material concerning its degradation by enzymes in the colonic microflora and its drug release behavior in a sustained and controlled manner. INU is a polysaccharide and it consists of 2 to 1 linkage having an extensive array of beneficial uses such as a carrier for delivery of therapeutic agents as an indicative/investigative utensil or as a dietary fiber with added well-being aids. In the main, limited research, as well as information, is available on the delivery of therapeutic agents using inulin specifically for colon cancer because of its capability to subsist in the stomach's acidic medium. This exceptional steadiness and robustness properties are exploited in numerous patterns to target drugs securely for the management of colonic cancer, where they effectively act and kills colonic tumor cells easily. In this review article, recent efforts and inulin-based nano-technological approaches for colon cancer targeting are presented and discussed.},
	doi = {10.2174/1567201817666200527133719},
	pmid = {32459607 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/nu11051026,
	author = {Chen J and Zhao KN and Vitetta L},
	title = {Effects of Intestinal Microbial−Elaborated Butyrate on Oncogenic Signaling Pathways.},
	journal = {Nutrients},
	year = {2019},
	abstract = {The intestinal microbiota is well known to have multiple benefits on human health, including cancer prevention and treatment. The effects are partially mediated by microbiota-produced short chain fatty acids (SCFAs) such as butyrate, propionate and acetate. The anti-cancer effect of butyrate has been demonstrated in cancer cell cultures and animal models of cancer. Butyrate, as a signaling molecule, has effects on multiple signaling pathways. The most studied effect is its inhibition on histone deacetylase (HDAC), which leads to alterations of several important oncogenic signaling pathways such as JAK2/STAT3, VEGF. Butyrate can interfere with both mitochondrial apoptotic and extrinsic apoptotic pathways. In addition, butyrate also reduces gut inflammation by promoting T-regulatory cell differentiation with decreased activities of the NF-κB and STAT3 pathways. Through PKC and Wnt pathways, butyrate increases cancer cell differentiation. Furthermore, butyrate regulates oncogenic signaling molecules through microRNAs and methylation. Therefore, butyrate has the potential to be incorporated into cancer prevention and treatment regimens. In this review we summarize recent progress in butyrate research and discuss the future development of butyrate as an anti-cancer agent with emphasis on its effects on oncogenic signaling pathways. The low bioavailability of butyrate is a problem, which precludes clinical application. The disadvantage of butyrate for medicinal applications may be overcome by several approaches including nano-delivery, analogue development and combination use with other anti-cancer agents or phytochemicals.},
	doi = {10.3390/nu11051026},
	pmid = {31067776 [Indexed for MEDLINE]},
	note = {PMC6566851}
}
